from fastapi import FastAPI, File, UploadFile, HTTPException, Query
from fastapi.responses import JSONResponse
from pydantic import BaseModel
from typing import Dict, List, Optional
from pathlib import Path
import io
import os
import json
import time
import hashlib
import pickle
import logging

import numpy as np
from PIL import Image

try:
    import face_recognition
except Exception as e:
    raise RuntimeError("face_recognition package is required") from e

from sklearn.preprocessing import LabelEncoder
from sklearn.svm import SVC

APP_TITLE = "Office Security Facial Recognition API"
DATA_DIR = Path(os.getenv("FR_DATA_DIR", "./face_data"))
TRAIN_DIR = DATA_DIR / "employees"
MODEL_DIR = DATA_DIR / "model"
MODEL_PATH = MODEL_DIR / "face_classifier.pkl"
META_PATH = MODEL_DIR / "meta.json"

DATA_DIR.mkdir(parents=True, exist_ok=True)
TRAIN_DIR.mkdir(parents=True, exist_ok=True)
MODEL_DIR.mkdir(parents=True, exist_ok=True)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("face_api")

app = FastAPI(title=APP_TITLE)

class TrainResponse(BaseModel):
    status: str
    classes: List[str]
    samples_per_class: Dict[str, int]
    total_samples: int
    model_path: str

class PredictFaceResult(BaseModel):
    face_index: int
    box: Dict[str, int]
    probabilities: Dict[str, float]
    best_match: str
    best_match_confidence: float

class PredictResponse(BaseModel):
    status: str
    faces_detected: int
    results: List[PredictFaceResult]
    classes: List[str]

def sha256_bytes(b: bytes) -> str:
    h = hashlib.sha256()
    h.update(b)
    return h.hexdigest()

def load_image_bytes_to_rgb(image_bytes: bytes) -> np.ndarray:
    try:
        img = Image.open(io.BytesIO(image_bytes)).convert("RGB")
        return np.array(img)
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid image file: {e}")

def list_training_images() -> Dict[str, List[Path]]:
    classes = {}
    for person_dir in sorted(TRAIN_DIR.iterdir()):
        if person_dir.is_dir():
            imgs = []
            for ext in ("*.jpg", "*.jpeg", "*.png", "*.bmp", "*.webp"):
                imgs.extend(person_dir.glob(ext))
            if imgs:
                classes[person_dir.name] = sorted(imgs)
    return classes

def encode_face_from_image_path(image_path: Path, model: str = "hog") -> Optional[np.ndarray]:
    image = face_recognition.load_image_file(str(image_path))
    boxes = face_recognition.face_locations(image, model=model)
    if len(boxes) == 0:
        return None
    encs = face_recognition.face_encodings(image, known_face_locations=boxes)
    if len(encs) == 0:
        return None
    if len(encs) == 1:
        return encs[0]
    areas = []
    for top, right, bottom, left in boxes:
        areas.append(max(0, bottom - top) * max(0, right - left))
    idx = int(np.argmax(areas))
    return encs[idx]

def train_classifier(detection_model: str = "hog") -> TrainResponse:
    class_to_images = list_training_images()
    if not class_to_images:
        raise HTTPException(status_code=400, detail="No training images found in employees directory")

    X = []
    y = []
    samples_per_class = {}

    for person, image_paths in class_to_images.items():
        count = 0
        for image_path in image_paths:
            enc = encode_face_from_image_path(image_path, model=detection_model)
            if enc is not None:
                X.append(enc)
                y.append(person)
                count += 1
            else:
                logger.warning("No usable face found in %s", image_path)
        if count > 0:
            samples_per_class[person] = count

    if not X or len(set(y)) < 2:
        raise HTTPException(
            status_code=400,
            detail="Need at least 2 classes with valid face encodings to train"
        )

    X = np.array(X)
    y = np.array(y)

    le = LabelEncoder()
    y_enc = le.fit_transform(y)

    clf = SVC(kernel="linear", probability=True, class_weight="balanced")
    clf.fit(X, y_enc)

    payload = {
        "classifier": clf,
        "label_encoder": le,
    }
    with open(MODEL_PATH, "wb") as f:
        pickle.dump(payload, f)

    meta = {
        "trained_at": int(time.time()),
        "classes": list(le.classes_),
        "samples_per_class": samples_per_class,
        "total_samples": int(len(X)),
        "detection_model": detection_model,
    }
    with open(META_PATH, "w", encoding="utf-8") as f:
        json.dump(meta, f, indent=2)

    return TrainResponse(
        status="trained",
        classes=list(le.classes_),
        samples_per_class=samples_per_class,
        total_samples=int(len(X)),
        model_path=str(MODEL_PATH),
    )

def load_model():
    if not MODEL_PATH.exists():
        raise HTTPException(status_code=404, detail="Model not trained yet")
    with open(MODEL_PATH, "rb") as f:
        payload = pickle.load(f)
    clf = payload["classifier"]
    le = payload["label_encoder"]
    return clf, le

def detect_and_predict(image_bytes: bytes, detection_model: str = "hog") -> PredictResponse:
    clf, le = load_model()
    rgb = load_image_bytes_to_rgb(image_bytes)
    boxes = face_recognition.face_locations(rgb, model=detection_model)
    if not boxes:
        return PredictResponse(status="ok", faces_detected=0, results=[], classes=list(le.classes_))

    encs = face_recognition.face_encodings(rgb, known_face_locations=boxes)
    results = []

    for idx, (box, enc) in enumerate(zip(boxes, encs)):
        probs = clf.predict_proba([enc])[0]
        class_probs = {cls: float(prob) for cls, prob in zip(le.classes_, probs)}
        best_i = int(np.argmax(probs))
        best_match = str(le.classes_[best_i])
        best_conf = float(probs[best_i])

        top, right, bottom, left = box
        results.append(
            PredictFaceResult(
                face_index=idx,
                box={"top": int(top), "right": int(right), "bottom": int(bottom), "left": int(left)},
                probabilities=class_probs,
                best_match=best_match,
                best_match_confidence=best_conf,
            )
        )

    return PredictResponse(
        status="ok",
        faces_detected=len(results),
        results=results,
        classes=list(le.classes_),
    )

@app.get("/health")
def health():
    return {"status": "ok"}

@app.post("/employees/{employee_id}/photos")
async def upload_employee_photo(employee_id: str, file: UploadFile = File(...)):
    employee_id = employee_id.strip()
    if not employee_id:
        raise HTTPException(status_code=400, detail="employee_id cannot be empty")

    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty file")

    _ = load_image_bytes_to_rgb(content)

    person_dir = TRAIN_DIR / employee_id
    person_dir.mkdir(parents=True, exist_ok=True)

    ext = Path(file.filename or "upload.jpg").suffix.lower()
    if ext not in {".jpg", ".jpeg", ".png", ".bmp", ".webp"}:
        ext = ".jpg"

    filename = f"{sha256_bytes(content)[:16]}{ext}"
    out_path = person_dir / filename
    with open(out_path, "wb") as f:
        f.write(content)

    return {
        "status": "uploaded",
        "employee_id": employee_id,
        "file": str(out_path),
    }

@app.post("/train", response_model=TrainResponse)
def train(detection_model: str = Query("hog", pattern="^(hog|cnn)$")):
    return train_classifier(detection_model=detection_model)

@app.post("/recognize", response_model=PredictResponse)
async def recognize(
    file: UploadFile = File(...),
    detection_model: str = Query("hog", pattern="^(hog|cnn)$")
):
    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty file")
    return detect_and_predict(content, detection_model=detection_model)

@app.get("/classes")
def classes():
    if not META_PATH.exists():
        raise HTTPException(status_code=404, detail="Model metadata not found")
    with open(META_PATH, "r", encoding="utf-8") as f:
        return JSONResponse(content=json.load(f))

@app.get("/employees")
def employees():
    class_to_images = list_training_images()
    return {
        "employees": [
            {"employee_id": person, "photos": [str(p) for p in paths], "count": len(paths)}
            for person, paths in class_to_images.items()
        ]
    }

